1	import { useMarkets } from "@/lib/query/hooks";
2	import { useAssumptions } from "./AssumptionContext";
3	import { AssumptionBar } from "./AssumptionBar";
4	import { VariableRow } from "./VariableRow";
5	import type { Market } from "@/lib/api/types";
6	
7	interface AssumptionPanelProps {
8	  market: Market;
9	}
10	
11	export function AssumptionPanel({ market }: AssumptionPanelProps) {
12	  const { data: marketsData } = useMarkets();
13	  const { assumptions } = useAssumptions();
14	
15	  const allMarkets = marketsData?.markets ?? [];
16	  const activeMarkets = allMarkets.filter((m) => m.status === "active");
17	
18	  // Show current market first, then others
19	  const sortedIds = [
20	    market.id,
21	    ...activeMarkets.filter((m) => m.id !== market.id).map((m) => m.id),
22	  ];
23	
24	  return (
25	    <div style={panelStyle}>
26	      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "baseline", marginBottom: "var(--space-sm)" }}>
27	        <h3 style={{ fontSize: "1rem", fontWeight: 600 }}>
28	          Variables & Assumptions
29	        </h3>
30	        <span style={{ fontSize: "0.75rem", color: "var(--color-text-muted)" }}>
31	          {assumptions.length > 0
32	            ? `Showing conditionals given ${assumptions.length} assumption${assumptions.length > 1 ? "s" : ""}`
33	            : "Showing marginal probabilities"}
34	        </span>
35	      </div>
36	
37	      <AssumptionBar />
38	
39	      <div style={{ display: "grid", gap: "var(--space-sm)", marginTop: "var(--space-sm)" }}>
40	        {sortedIds.map((id) => (
41	          <VariableRow key={id} marketId={id} targetMarket={market} />
42	        ))}
43	      </div>
44	
45	      {activeMarkets.length <= 1 && (
46	        <div style={{ fontSize: "0.8rem", color: "var(--color-text-muted)", textAlign: "center", padding: "var(--space-md)" }}>
47	          Create more markets to use assumptions — assumptions let you condition on other variables.
48	        </div>
49	      )}
50	    </div>
51	  );
52	}
53	
54	const panelStyle: React.CSSProperties = {
55	  padding: "var(--space-md)",
56	  borderRadius: "var(--radius-md)",
57	  border: "1px solid var(--color-border)",
58	  background: "var(--color-bg-surface)",
59	};
